INSERT INTO invoice_templates VALUES(2,'rechnungen','',replace('\n                <div style="padding: 20mm; font-family: Arial, sans-serif; font-size: 12px; position: relative;">\n                    <!-- Company Header -->\n                    <div style="text-align: right; margin-bottom: 30px; position: relative; font-size: 12px;">\n                        <div style="font-weight: bold; font-size: 16px; position: relative;"></div>\n                        <div style="position: relative; font-size: 12px;"></div>\n                        <div style="position: relative; font-size: 12px;"> </div>\n                        <div style="position: relative; font-size: 12px;">Tel: </div>\n                        <div style="position: relative; font-size: 12px;">E-Mail: </div>\n                    </div>\n\n                    <!-- Sender Address Line -->\n                    <div style="font-size: 8px; margin-bottom: 10px; border-bottom: 1px solid rgb(0, 0, 0); padding-bottom: 5px; position: relative;">\n                        , ,  \n                    </div>\n\n                    <!-- Customer Address -->\n                    <div style="margin-bottom: 30px; position: relative; font-size: 12px;">\n                        <div style="font-weight: bold; position: relative; font-size: 12px;"></div>\n                        <div style="position: relative; font-size: 12px;"></div>\n                        <div style="position: relative; font-size: 12px;"> </div>\n                    </div>\n\n                    <!-- Invoice Header -->\n                    <h1 style="font-size: 24px; font-weight: bold; margin-bottom: 20px; position: relative; color: rgb(37, 99, 235);">RECHNUNG</h1>\n\n                    <!-- Invoice Details -->\n                    <table style="width: 100%; margin-bottom: 20px; border-collapse: collapse; position: relative;">\n                        <tbody><tr>\n                            <td style="width: 30%; padding: 5px 0px; font-size: 12px;">Rechnungsnummer:</td>\n                            <td style="font-weight: bold; font-size: 12px;"></td>\n                        </tr>\n                        <tr>\n                            <td style="padding: 5px 0px; font-size: 12px;">Rechnungsdatum:</td>\n                            <td style="font-size: 12px;"></td>\n                        </tr>\n                        <tr>\n                            <td style="padding: 5px 0px; font-size: 12px;">Fälligkeitsdatum:</td>\n                            <td style="font-size: 12px;"></td>\n                        </tr>\n                        <tr>\n                            <td style="padding: 5px 0px; font-size: 12px;">Kundennummer:</td>\n                            <td style="font-size: 12px;"></td>\n                        </tr>\n                    </tbody></table>\n\n                    <!-- Line Items -->\n                    <table style="width: 100%; border-collapse: collapse; margin-bottom: 20px; position: relative;">\n                        <thead>\n                            <tr style="background: #f5f5f5;">\n                                <th style="border: 1px solid #000; padding: 8px; text-align: left;">Pos.</th>\n                                <th style="border: 1px solid #000; padding: 8px; text-align: left;">Beschreibung</th>\n                                <th style="border: 1px solid #000; padding: 8px; text-align: center;">Menge</th>\n                                <th style="border: 1px solid #000; padding: 8px; text-align: right;">Einzelpreis</th>\n                                <th style="border: 1px solid #000; padding: 8px; text-align: right;">Gesamtpreis</th>\n                            </tr>\n                        </thead>\n                        <tbody>\n                            <tr>\n                                <td style="border: 1px solid rgb(0, 0, 0); padding: 8px; font-size: 12px;">1</td>\n                                <td style="border: 1px solid rgb(0, 0, 0); padding: 8px; font-size: 12px;"></td>\n                                <td style="border: 1px solid rgb(0, 0, 0); padding: 8px; text-align: center; font-size: 12px;">1</td>\n                                <td style="border: 1px solid rgb(0, 0, 0); padding: 8px; text-align: right; font-size: 12px;">100,00 €</td>\n                                <td style="border: 1px solid rgb(0, 0, 0); padding: 8px; text-align: right; font-size: 12px;">100,00 €</td>\n                            </tr>\n                        </tbody>\n                    </table>\n\n                    <!-- Totals -->\n                    <div style="text-align: right; margin-bottom: 30px; position: relative; font-size: 12px;">\n                        <table style="width: 200px; margin-left: auto; border-collapse: collapse; position: relative;">\n                            <tbody><tr>\n                                <td style="padding: 5px 10px; border-bottom: 1px solid rgb(221, 221, 221); font-size: 12px;">Nettobetrag:</td>\n                                <td style="text-align: right; padding: 5px 10px; border-bottom: 1px solid rgb(221, 221, 221); font-size: 12px;">%!f(<nil>) €</td>\n                            </tr>\n                            <tr>\n                                <td style="padding: 5px 10px; border-bottom: 1px solid rgb(221, 221, 221); font-size: 12px;">MwSt. (19%):</td>\n                                <td style="text-align: right; padding: 5px 10px; border-bottom: 1px solid rgb(221, 221, 221); font-size: 12px;">%!f(<nil>) €</td>\n                            </tr>\n                            <tr style="font-weight: bold; border-top: 2px solid #000;">\n                                <td style="padding: 8px 10px; font-size: 12px;">Gesamtbetrag:</td>\n                                <td style="text-align: right; padding: 8px 10px; font-size: 12px;">%!f(<nil>) €</td>\n                            </tr>\n                        </tbody></table>\n                    </div>\n\n                    <!-- Footer -->\n                    <div style="font-size: 10px; margin-top: 40px; border-top: 1px solid rgb(221, 221, 221); padding-top: 20px; position: relative;">\n                        <div style="text-align: center; position: relative; font-size: 12px;">\n                            <div style="position: relative; font-size: 12px;">Steuernummer:  | USt-IdNr.: </div>\n                            <div style="margin-top: 10px; position: relative; font-size: 12px;">\n                                Zahlungsziel: 14 Tage netto | Bankverbindung: IBAN DE12 3456 7890 1234 5678 90\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            <img src="data:image/png;base64," style="max-height: 60px; position: absolute; top: 20px; left: 20px; cursor: move;">','\n',char(10)),'{"primaryFont":"Arial","headerFontSize":"24","bodyFontSize":"12","primaryColor":"#2563eb","accentColor":"#64748b","textColor":"#000000","backgroundColor":"#ffffff","pageMargins":"20","elementSpacing":"15","borderStyle":"none","logoPosition":"top-left","logoSize":"large","templateType":"german-din"}',0,1,5,'2025-06-17 21:37:20','2025-06-17 22:11:49');
INSERT INTO email_templates VALUES(1,'Default Invoice Template','Standard invoice email template','invoice','Invoice {{.invoice.InvoiceNumber}} - {{.company.CompanyName}}',replace(replace('<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset="UTF-8">\r\n    <title>Invoice</title>\r\n</head>\r\n<body>\r\n    <h1>Invoice {{.invoice.InvoiceNumber}}</h1>\r\n    <p>Dear {{.customer.GetDisplayName}},</p>\r\n    <p>Please find attached your invoice for the amount of {{.settings.CurrencySymbol}}{{.invoice.TotalAmount}}.</p>\r\n    <p>Due date: {{.invoice.DueDate.Format "02.01.2006"}}</p>\r\n    <p>Best regards,<br>{{.company.CompanyName}}</p>\r\n</body>\r\n</html>','\r',char(13)),'\n',char(10)),replace(replace('Invoice {{.invoice.InvoiceNumber}}\r\n\r\nDear {{.customer.GetDisplayName}},\r\n\r\nPlease find attached your invoice for the amount of {{.settings.CurrencySymbol}}{{.invoice.TotalAmount}}.\r\n\r\nDue date: {{.invoice.DueDate.Format "02.01.2006"}}\r\n\r\nBest regards,\r\n{{.company.CompanyName}}','\r',char(13)),'\n',char(10)),1,1,NULL,'2025-07-14 05:51:02','2025-07-14 05:51:02');
INSERT INTO email_templates VALUES(2,'Default Payment Reminder','Standard payment reminder template','reminder','Payment Reminder - Invoice {{.invoice.InvoiceNumber}}',replace(replace('<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset="UTF-8">\r\n    <title>Payment Reminder</title>\r\n</head>\r\n<body>\r\n    <h1>Payment Reminder</h1>\r\n    <p>Dear {{.customer.GetDisplayName}},</p>\r\n    <p>This is a friendly reminder that invoice {{.invoice.InvoiceNumber}} with an outstanding balance of {{.settings.CurrencySymbol}}{{.invoice.BalanceDue}} is now overdue.</p>\r\n    <p>Original due date: {{.invoice.DueDate.Format "02.01.2006"}}</p>\r\n    <p>Please process payment at your earliest convenience.</p>\r\n    <p>Best regards,<br>{{.company.CompanyName}}</p>\r\n</body>\r\n</html>','\r',char(13)),'\n',char(10)),replace(replace('Payment Reminder - Invoice {{.invoice.InvoiceNumber}}\r\n\r\nDear {{.customer.GetDisplayName}},\r\n\r\nThis is a friendly reminder that invoice {{.invoice.InvoiceNumber}} with an outstanding balance of {{.settings.CurrencySymbol}}{{.invoice.BalanceDue}} is now overdue.\r\n\r\nOriginal due date: {{.invoice.DueDate.Format "02.01.2006"}}\r\n\r\nPlease process payment at your earliest convenience.\r\n\r\nBest regards,\r\n{{.company.CompanyName}}','\r',char(13)),'\n',char(10)),1,1,NULL,'2025-07-14 05:51:02','2025-07-14 05:51:02');
