INSERT INTO insurances VALUES(1,'Kfz-Versicherung',1,'619/479700-F',replace(replace('Kfz-Haftpflichtversicherung\r\n✓ Leistet, wenn mit dem versicherten Fahrzeug\r\nAndere geschädigt werden\r\n✓ Ersetzt berechtigte Ansprüche\r\n✓ Wehrt unberechtigte Forderungen ab\r\nAutoschutzbrief\r\n✓ Bietet organisatorische und finanzielle Hilfe bei\r\nPanne oder Unfall Ihres Fahrzeugs\r\nTeilkasko\r\n✓ Ersetzt Schäden an Ihrem Fahrzeug\r\n✓ Versichert sind z. B. Diebstahl, Hagel, Sturm oder\r\nBruch der Verglasung\r\nVollkasko\r\n✓ Ersetzt zusätzlich zur Teilkasko Schäden an Ihrem\r\nFahrzeug durch Vandalismus oder Unfall\r\nFahrerschutz\r\n✓ Ersetzt den Personenschaden des Fahrers durch\r\neinen Unfall beim Gebrauch des Fahrzeugs; auch\r\nfür Insassen\r\nAusland-Schadenschutz\r\n✓ Ersetzt Ihren Personen- und Sachschaden bei\r\neinem Unfall im Ausland, bei dem der Unfallgegner\r\nhaftet, so als ob dieser bei uns kfz-haftpflichtversichert\r\nwäre\r\nKfz-Umweltschadenversicherung\r\n✓ Schützt Sie vor öffentlich-rechtlichen Ansprüchen\r\nnach dem Umweltschadensgesetz\r\nVersicherungssumme\r\n✓ Die Höhe der Versicherungssumme je Schadenereignis\r\nkönnen Sie Ihrem Versicherungsantrag und\r\nIhrem Versicherungsschein entnehmen.','\r',char(13)),'\n',char(10)),NULL,46.0900000000000034);
